import { Component, computed, signal } from '@angular/core';
import { RouterLink } from '@angular/router';
import { Category, Source } from '../../../core/models';

@Component({
  selector: 'app-admin-dashboard',
  standalone: true,
  imports: [RouterLink],
  templateUrl: './admin-dashboard.component.html',
  styleUrl: './admin-dashboard.component.css',
})
export class AdminDashboardComponent {
  // --- Backend-provided data (mock). ---
  sources = signal<Source[]>([
    {
      id: 's1',
      name: 'The Verge',
      url: 'https://www.theverge.com/rss/index.xml',
      category: 'Technology',
      categorySlug: 'tech',
      active: true,
      lastFetchedAt: this.minsAgo(4),
      lastError: null,
      articleCount: 128,
    },
    {
      id: 's2',
      name: 'Reuters Business',
      url: 'https://feeds.reuters.com/reuters/businessNews',
      category: 'Business',
      categorySlug: 'business',
      active: true,
      lastFetchedAt: this.minsAgo(4),
      lastError: null,
      articleCount: 94,
    },
    {
      id: 's3',
      name: 'BBC World',
      url: 'https://feeds.bbci.co.uk/news/world/rss.xml',
      category: 'World News',
      categorySlug: 'world',
      active: true,
      lastFetchedAt: this.minsAgo(4),
      lastError: null,
      articleCount: 156,
    },
    {
      id: 's4',
      name: 'Indie Sports Blog',
      url: 'https://indie-sports.example.com/feed',
      category: 'Sports',
      categorySlug: 'sports',
      active: true,
      lastFetchedAt: this.hoursAgo(6),
      lastError: 'Request timed out after 10s',
      articleCount: 41,
    },
    {
      id: 's5',
      name: 'Science Daily',
      url: 'https://www.sciencedaily.com/rss/all.xml',
      category: 'Science',
      categorySlug: 'science',
      active: false,
      lastFetchedAt: this.hoursAgo(30),
      lastError: '404 Not Found — feed URL may have moved',
      articleCount: 63,
    },
  ]);

  categories = signal<Category[]>([
    { id: 'c1', name: 'Technology', slug: 'tech', articleCount: 128 },
    { id: 'c2', name: 'World News', slug: 'world', articleCount: 156 },
    { id: 'c3', name: 'Business', slug: 'business', articleCount: 94 },
    { id: 'c4', name: 'Sports', slug: 'sports', articleCount: 41 },
    { id: 'c5', name: 'Science', slug: 'science', articleCount: 63 },
  ]);

  // --- Derived KPIs ---
  totalSources = computed(() => this.sources().length);
  activeSources = computed(() => this.sources().filter((s) => s.active).length);
  totalCategories = computed(() => this.categories().length);
  totalArticles = computed(() =>
    this.sources().reduce((sum, s) => sum + s.articleCount, 0),
  );
  failingSources = computed(() => this.sources().filter((s) => !!s.lastError));

  // --- Refresh interaction ---
  refreshing = signal(false);
  refreshStatus = signal<string | null>(null);

  refreshAll(): void {
    this.refreshing.set(true);
    this.refreshStatus.set(null);
    // Simulate a POST /admin/refresh -> 202 Accepted (jobs enqueued).
    setTimeout(() => {
      this.refreshing.set(false);
      this.refreshStatus.set(
        `Refresh queued for ${this.activeSources()} active source(s). New articles will appear shortly.`,
      );
    }, 900);
  }

  timeAgo(iso: string | null): string {
    if (!iso) return 'never';
    const then = new Date(iso).getTime();
    const mins = Math.round((Date.now() - then) / 60000);
    if (mins < 1) return 'just now';
    if (mins < 60) return `${mins}m ago`;
    const hours = Math.round(mins / 60);
    if (hours < 24) return `${hours}h ago`;
    return `${Math.round(hours / 24)}d ago`;
  }

  private minsAgo(m: number): string {
    return new Date(Date.now() - m * 60_000).toISOString();
  }
  private hoursAgo(h: number): string {
    return new Date(Date.now() - h * 3_600_000).toISOString();
  }
}
